package org.apache.commons.csv;

import static org.apache.commons.csv.Constants.CR;
import static org.apache.commons.csv.Constants.LF;
import static org.apache.commons.csv.Constants.UNDEFINED;
import static org.junit.jupiter.api.Assertions.assertFalse;
import static org.junit.jupiter.api.Assertions.assertTrue;

import java.lang.reflect.Method;

import org.apache.commons.csv.Lexer;
import org.apache.commons.csv.CSVFormat;
import org.apache.commons.csv.ExtendedBufferedReader;
import org.apache.commons.csv.Token;
import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.mockito.Mockito;

class LexerIsStartOfLineTest {

    private Lexer lexer;

    @BeforeEach
    void setUp() {
        CSVFormat format = Mockito.mock(CSVFormat.class);
        ExtendedBufferedReader in = Mockito.mock(ExtendedBufferedReader.class);
        lexer = new Lexer(format, in) {
            @Override
            Token nextToken(Token reusableToken) {
                return null;
            }
        };
    }

    @Test
    void testIsStartOfLine_LF_ReturnsTrue() throws Exception {
        Method method = Lexer.class.getDeclaredMethod("isStartOfLine", int.class);
        method.setAccessible(true);
        assertTrue((Boolean) method.invoke(lexer, LF));
    }

    @Test
    void testIsStartOfLine_CR_ReturnsTrue() throws Exception {
        Method method = Lexer.class.getDeclaredMethod("isStartOfLine", int.class);
        method.setAccessible(true);
        assertTrue((Boolean) method.invoke(lexer, CR));
    }

    @Test
    void testIsStartOfLine_UNDEFINED_ReturnsTrue() throws Exception {
        Method method = Lexer.class.getDeclaredMethod("isStartOfLine", int.class);
        method.setAccessible(true);
        assertTrue((Boolean) method.invoke(lexer, UNDEFINED));
    }

    @Test
    void testIsStartOfLine_OtherChar_ReturnsFalse() throws Exception {
        Method method = Lexer.class.getDeclaredMethod("isStartOfLine", int.class);
        method.setAccessible(true);
        assertFalse((Boolean) method.invoke(lexer, 'a'));
        assertFalse((Boolean) method.invoke(lexer, 0));
        assertFalse((Boolean) method.invoke(lexer, 32)); // space
        assertFalse((Boolean) method.invoke(lexer, 255));
    }
}
